"use client"

import { useState, useRef, useEffect } from "react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Avatar, AvatarFallback } from "@/components/ui/avatar"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { sendMessage, type Message } from "@/lib/api"

function MessageBubble({ message }: { message: Message }) {
  const isUser = message.role === "user"

  return (
    <div className={`flex gap-3 ${isUser ? "flex-row-reverse" : "flex-row"}`}>
      <Avatar className="h-8 w-8 shrink-0">
        <AvatarFallback className={isUser ? "bg-zinc-800 text-white" : "bg-zinc-200 text-zinc-800"}>
          {isUser ? "U" : "AI"}
        </AvatarFallback>
      </Avatar>

      <div
        className={`max-w-[75%] rounded-2xl px-4 py-2.5 text-sm leading-relaxed whitespace-pre-wrap break-words ${
          isUser
            ? "bg-zinc-800 text-white rounded-tr-sm"
            : "bg-zinc-100 text-zinc-900 rounded-tl-sm"
        }`}
      >
        {message.content}
      </div>
    </div>
  )
}

function TypingIndicator() {
  return (
    <div className="flex gap-3">
      <Avatar className="h-8 w-8 shrink-0">
        <AvatarFallback className="bg-zinc-200 text-zinc-800">AI</AvatarFallback>
      </Avatar>
      <div className="bg-zinc-100 rounded-2xl rounded-tl-sm px-4 py-3 flex gap-1 items-center">
        <span className="w-1.5 h-1.5 bg-zinc-400 rounded-full animate-bounce [animation-delay:0ms]" />
        <span className="w-1.5 h-1.5 bg-zinc-400 rounded-full animate-bounce [animation-delay:150ms]" />
        <span className="w-1.5 h-1.5 bg-zinc-400 rounded-full animate-bounce [animation-delay:300ms]" />
      </div>
    </div>
  )
}

const EXAMPLE_QUESTIONS = [
  "What log files are available?",
  "Read sample_app.log",
  "Search for ERROR in sample_app.log",
  "Summarise everything and save it",
]

export function Chat() {
  const [messages, setMessages] = useState<Message[]>([])
  const [input, setInput] = useState("")
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const bottomRef = useRef<HTMLDivElement>(null)
  const inputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" })
  }, [messages, loading])

  async function handleSubmit(message: string) {
    if (!message.trim() || loading) return

    const userMessage: Message = {
      id: crypto.randomUUID(),
      role: "user",
      content: message.trim(),
    }

    setMessages((prev) => [...prev, userMessage])
    setInput("")
    setError(null)
    setLoading(true)

    try {
      const response = await sendMessage(message.trim())
      const assistantMessage: Message = {
        id: crypto.randomUUID(),
        role: "assistant",
        content: response,
      }
      setMessages((prev) => [...prev, assistantMessage])
    } catch (err) {
      setError(err instanceof Error ? err.message : "Something went wrong")
    } finally {
      setLoading(false)
      inputRef.current?.focus()
    }
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLInputElement>) {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault()
      handleSubmit(input)
    }
  }

  function clearChat() {
    setMessages([])
    setError(null)
    inputRef.current?.focus()
  }

  return (
    <div className="flex h-screen gap-4 p-4 bg-zinc-50">

      {/* Sidebar */}
      <Card className="w-64 shrink-0 flex flex-col h-full">
        <CardHeader className="pb-3">
          <CardTitle className="text-base">AI Log Analyzer</CardTitle>
          <p className="text-xs text-zinc-500">Agents SDK · LiteLLM · Gemini</p>
        </CardHeader>

        <CardContent className="flex flex-col gap-4 flex-1 overflow-auto">
          <div>
            <p className="text-xs font-medium text-zinc-500 uppercase tracking-wide mb-2">
              Try asking
            </p>
            <div className="flex flex-col gap-1.5">
              {EXAMPLE_QUESTIONS.map((q) => (
                <button
                  key={q}
                  onClick={() => handleSubmit(q)}
                  disabled={loading}
                  className="text-left text-xs text-zinc-600 hover:text-zinc-900 hover:bg-zinc-100 rounded-lg px-2.5 py-1.5 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {q}
                </button>
              ))}
            </div>
          </div>

          <div className="mt-auto">
            <Button
              variant="outline"
              size="sm"
              onClick={clearChat}
              className="w-full text-xs"
              disabled={loading || messages.length === 0}
            >
              Clear chat
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Chat area */}
      <Card className="flex-1 flex flex-col h-full overflow-hidden">

        {/* Messages */}
        <ScrollArea className="flex-1 px-4 pt-4">
          {messages.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center py-20 gap-2">
              <p className="text-sm font-medium text-zinc-700">Ask me about your logs</p>
              <p className="text-xs text-zinc-400">
                I can read, search, and analyse your log files
              </p>
            </div>
          ) : (
            <div className="flex flex-col gap-4 pb-4">
              {messages.map((m) => (
                <MessageBubble key={m.id} message={m} />
              ))}
              {loading && <TypingIndicator />}
              {error && (
                <div className="text-xs text-red-500 bg-red-50 border border-red-100 rounded-lg px-3 py-2">
                  {error}
                </div>
              )}
              <div ref={bottomRef} />
            </div>
          )}
        </ScrollArea>

        {/* Input */}
        <div className="p-4 border-t border-zinc-100">
          <div className="flex gap-2">
            <Input
              ref={inputRef}
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Ask about your logs..."
              disabled={loading}
              className="flex-1 text-sm"
              autoFocus
            />
            <Button
              onClick={() => handleSubmit(input)}
              disabled={loading || !input.trim()}
              size="sm"
              className="px-4"
            >
              Send
            </Button>
          </div>
          <p className="text-[10px] text-zinc-400 mt-1.5 px-1">
            Press Enter to send
          </p>
        </div>
      </Card>

    </div>
  )
}